package main.rice;

import main.rice.basegen.BaseSetGenerator;
import main.rice.concisegen.ConciseSetGenerator;
import main.rice.node.APyNode;
import main.rice.parse.ConfigFile;
import main.rice.parse.ConfigFileParser;
import main.rice.parse.InvalidConfigException;
import main.rice.test.TestCase;
import main.rice.test.TestResults;
import main.rice.test.Tester;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.List;
import java.util.Set;

/**
 * The entry point for the test generation system. Ties together parsing, test generation,
 * test execution, and concise set selection.
 */
public class Main {

    /**
     * Generates a minimal set of test cases that catch all known buggy implementations.
     *
     * @param args [configPath, solutionPath, implDirPath]
     * @return a minimal set of TestCases that catch all known bugs
     * @throws IOException              if a file cannot be read/written
     * @throws InvalidConfigException   if the config file is invalid
     * @throws InterruptedException     if a subprocess is interrupted
     */
    public static Set<TestCase> generateTests(String[] args)
            throws IOException, InvalidConfigException, InterruptedException {
        String configPath = args[0];
        String solutionPath = args[1];
        String implDirPath = args[2];

        // Step 1: Parse the config file
        String configContent = Files.readString(Paths.get(configPath));
        ConfigFileParser parser = new ConfigFileParser();
        ConfigFile config = parser.parse(configContent);

        // Step 2: Generate the base test set
        List<APyNode<?>> nodes = config.getNodes();
        int numRand = config.getNumRand();
        BaseSetGenerator baseGen = new BaseSetGenerator(nodes, numRand);
        List<TestCase> baseSet = baseGen.genBaseSet();

        // Step 3: Run tests on all implementations
        Tester tester = new Tester(config.getFuncName(), solutionPath, implDirPath, baseSet);
        tester.computeExpectedResults();
        TestResults results = tester.runTests();

        // Step 4: Select the concise (minimal) test set
        return ConciseSetGenerator.setCover(results);
    }
}

package main.rice.parse;

import main.rice.node.APyNode;
import java.util.List;

/**
 * A simple data class representing a parsed configuration file.
 */
public class ConfigFile {

    private final String funcName;
    private final List<APyNode<?>> nodes;
    private final int numRand;

    /**
     * Constructs a ConfigFile with the given function name, nodes, and numRand.
     *
     * @param funcName the name of the function under test
     * @param nodes    the list of APyNodes representing the function's parameters
     * @param numRand  the number of random test cases to generate
     */
    public ConfigFile(String funcName, List<APyNode<?>> nodes, int numRand) {
        this.funcName = funcName;
        this.nodes = nodes;
        this.numRand = numRand;
    }

    /**
     * Returns the function name.
     *
     * @return the function name
     */
    public String getFuncName() {
        return this.funcName;
    }

    /**
     * Returns the list of APyNodes for the function's parameters.
     *
     * @return the list of APyNodes
     */
    public List<APyNode<?>> getNodes() {
        return this.nodes;
    }

    /**
     * Returns the number of random test cases.
     *
     * @return numRand
     */
    public int getNumRand() {
        return this.numRand;
    }
}

package main.rice.parse;

import main.rice.node.*;
import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;

import java.util.ArrayList;
import java.util.List;

/**
 * Parses a JSON configuration file into a ConfigFile object.
 */
public class ConfigFileParser {

    /** Default character domain for PyStringNodes. */
    private static final String DEFAULT_CHAR_DOMAIN = "abcdefghijklmnopqrstuvwxyz";

    /**
     * Parses the given JSON string into a ConfigFile.
     *
     * @param content the JSON string to parse
     * @return a ConfigFile parsed from the input
     * @throws InvalidConfigException if the content is invalid
     */
    public ConfigFile parse(String content) throws InvalidConfigException {
        // Parse as JSON
        JSONObject obj;
        try {
            obj = new JSONObject(content);
        } catch (JSONException e) {
            throw new InvalidConfigException("Content is not valid JSON: " + e.getMessage());
        }

        // Check for required fields
        if (!obj.has("fname")) throw new InvalidConfigException("Missing required field: fname");
        if (!obj.has("types")) throw new InvalidConfigException("Missing required field: types");
        if (!obj.has("exhaustive domain"))
            throw new InvalidConfigException("Missing required field: exhaustive domain");
        if (!obj.has("random domain"))
            throw new InvalidConfigException("Missing required field: random domain");
        if (!obj.has("num random"))
            throw new InvalidConfigException("Missing required field: num random");

        // Validate and extract fname
        Object fnameObj = obj.get("fname");
        if (!(fnameObj instanceof String)) {
            throw new InvalidConfigException("fname must be a string");
        }
        String fname = (String) fnameObj;

        // Validate and extract num random
        Object numRandObj = obj.get("num random");
        if (!(numRandObj instanceof Integer) && !(numRandObj instanceof Long)) {
            throw new InvalidConfigException("num random must be an integer");
        }
        int numRand = ((Number) numRandObj).intValue();
        if (numRand < 0) {
            throw new InvalidConfigException("num random must be non-negative");
        }

        // Validate and extract types
        Object typesObj = obj.get("types");
        if (!(typesObj instanceof JSONArray)) {
            throw new InvalidConfigException("types must be an array");
        }
        JSONArray typesArray = (JSONArray) typesObj;
        List<String> typeStrings = new ArrayList<>();
        for (int i = 0; i < typesArray.length(); i++) {
            Object item = typesArray.get(i);
            if (!(item instanceof String)) {
                throw new InvalidConfigException("types must be an array of strings");
            }
            typeStrings.add((String) item);
        }

        // Validate and extract exhaustive domain
        Object exDomainObj = obj.get("exhaustive domain");
        if (!(exDomainObj instanceof JSONArray)) {
            throw new InvalidConfigException("exhaustive domain must be an array");
        }
        JSONArray exDomainArray = (JSONArray) exDomainObj;
        List<String> exDomainStrings = new ArrayList<>();
        for (int i = 0; i < exDomainArray.length(); i++) {
            Object item = exDomainArray.get(i);
            if (!(item instanceof String)) {
                throw new InvalidConfigException("exhaustive domain must be an array of strings");
            }
            exDomainStrings.add((String) item);
        }

        // Validate and extract random domain
        Object ranDomainObj = obj.get("random domain");
        if (!(ranDomainObj instanceof JSONArray)) {
            throw new InvalidConfigException("random domain must be an array");
        }
        JSONArray ranDomainArray = (JSONArray) ranDomainObj;
        List<String> ranDomainStrings = new ArrayList<>();
        for (int i = 0; i < ranDomainArray.length(); i++) {
            Object item = ranDomainArray.get(i);
            if (!(item instanceof String)) {
                throw new InvalidConfigException("random domain must be an array of strings");
            }
            ranDomainStrings.add((String) item);
        }

        // Check lengths are consistent
        int numParams = typeStrings.size();
        if (exDomainStrings.size() != numParams) {
            throw new InvalidConfigException(
                "exhaustive domain length does not match types length");
        }
        if (ranDomainStrings.size() != numParams) {
            throw new InvalidConfigException(
                "random domain length does not match types length");
        }

        // Parse each parameter
        List<APyNode<?>> nodes = new ArrayList<>();
        for (int i = 0; i < numParams; i++) {
            String typeStr = typeStrings.get(i);
            String exDomainStr = exDomainStrings.get(i);
            String ranDomainStr = ranDomainStrings.get(i);

            // Check for spaces in domain strings
            if (exDomainStr.contains(" ")) {
                throw new InvalidConfigException(
                    "Space found in exhaustive domain: " + exDomainStr);
            }
            if (ranDomainStr.contains(" ")) {
                throw new InvalidConfigException(
                    "Space found in random domain: " + ranDomainStr);
            }

            // Parse the type string to create the node tree
            APyNode<?> node = parseTypeString(typeStr);

            // Parse and set the exhaustive domain
            int[] exPos = {0};
            parseDomainForNode(node, exDomainStr, exPos, true);
            if (exPos[0] != exDomainStr.length()) {
                throw new InvalidConfigException(
                    "Spurious characters in exhaustive domain: " + exDomainStr);
            }

            // Parse and set the random domain
            int[] ranPos = {0};
            parseDomainForNode(node, ranDomainStr, ranPos, false);
            if (ranPos[0] != ranDomainStr.length()) {
                throw new InvalidConfigException(
                    "Spurious characters in random domain: " + ranDomainStr);
            }

            nodes.add(node);
        }

        return new ConfigFile(fname, nodes, numRand);
    }

    /**
     * Parses a type string and returns the corresponding APyNode.
     *
     * @param typeStr the type string (e.g. "int", "list(bool)")
     * @return the corresponding APyNode
     * @throws InvalidConfigException if the type string is invalid
     */
    private APyNode<?> parseTypeString(String typeStr) throws InvalidConfigException {
        int[] pos = {0};
        APyNode<?> node = parseTypeInternal(typeStr, pos);
        if (pos[0] != typeStr.length()) {
            throw new InvalidConfigException(
                "Spurious characters in type: " + typeStr);
        }
        return node;
    }

    /**
     * Recursively parses a type string using a position cursor.
     */
    @SuppressWarnings("unchecked")
    private APyNode<?> parseTypeInternal(String typeStr, int[] pos)
            throws InvalidConfigException {
        // Read identifier (letters only)
        int start = pos[0];
        while (pos[0] < typeStr.length() && Character.isLetter(typeStr.charAt(pos[0]))) {
            pos[0]++;
        }
        String name = typeStr.substring(start, pos[0]);

        switch (name) {
            case "int":
                return new PyIntNode();
            case "bool":
                return new PyBoolNode();
            case "float":
                return new PyFloatNode();
            case "str":
                return new PyStringNode(DEFAULT_CHAR_DOMAIN);
            case "list": {
                consumeTypeChar(typeStr, pos, '(');
                APyNode<?> inner = parseTypeInternal(typeStr, pos);
                consumeTypeChar(typeStr, pos, ')');
                return new PyListNode(inner);
            }
            case "set": {
                consumeTypeChar(typeStr, pos, '(');
                APyNode<?> inner = parseTypeInternal(typeStr, pos);
                consumeTypeChar(typeStr, pos, ')');
                return new PySetNode(inner);
            }
            case "tuple": {
                consumeTypeChar(typeStr, pos, '(');
                APyNode<?> inner = parseTypeInternal(typeStr, pos);
                consumeTypeChar(typeStr, pos, ')');
                return new PyTupleNode(inner);
            }
            case "dict": {
                consumeTypeChar(typeStr, pos, '(');
                APyNode<?> keyNode = parseTypeInternal(typeStr, pos);
                consumeTypeChar(typeStr, pos, ':');
                APyNode<?> valNode = parseTypeInternal(typeStr, pos);
                consumeTypeChar(typeStr, pos, ')');
                return new PyDictNode(keyNode, valNode);
            }
            default:
                throw new InvalidConfigException("Unknown type name: '" + name + "'");
        }
    }

    /**
     * Consumes the expected character from the type string at the current position.
     */
    private void consumeTypeChar(String typeStr, int[] pos, char expected)
            throws InvalidConfigException {
        if (pos[0] >= typeStr.length() || typeStr.charAt(pos[0]) != expected) {
            throw new InvalidConfigException(
                "Expected '" + expected + "' in type at position " + pos[0]
                    + ": " + typeStr);
        }
        pos[0]++;
    }

    /**
     * Parses domain string for a node tree using a cursor. Reads the domain spec for
     * this node and recursively handles child nodes using '(' as separator.
     *
     * @param node      the node to assign the domain to
     * @param domainStr the full domain string
     * @param pos       the current position cursor
     * @param isEx      true to set exhaustive domain, false for random domain
     * @throws InvalidConfigException if the domain is invalid
     */
    private void parseDomainForNode(APyNode<?> node, String domainStr, int[] pos,
                                    boolean isEx) throws InvalidConfigException {
        // Read the range spec for this node (until '(' or end)
        int start = pos[0];
        while (pos[0] < domainStr.length() && domainStr.charAt(pos[0]) != '(') {
            pos[0]++;
        }
        String rangeSpec = domainStr.substring(start, pos[0]);

        // Parse and set domain
        List<Number> domain = parseRangeSpec(rangeSpec);
        if (isEx) {
            node.setExDomain(domain);
        } else {
            node.setRanDomain(domain);
        }

        // Handle children based on node type
        if (node instanceof PyDictNode) {
            // Dict expects: outerRange(keyRange:valRange
            // Consume '('
            if (pos[0] >= domainStr.length() || domainStr.charAt(pos[0]) != '(') {
                throw new InvalidConfigException(
                    "Expected '(' for dict child domain in: " + domainStr);
            }
            pos[0]++;

            // Parse key domain (reads until '('; dict key domain uses ':' as separator)
            parseDomainForNodeWithColon(node.getLeftChild(), domainStr, pos, isEx);

            // Consume ':'
            if (pos[0] >= domainStr.length() || domainStr.charAt(pos[0]) != ':') {
                throw new InvalidConfigException(
                    "Expected ':' for dict value domain in: " + domainStr);
            }
            pos[0]++;

            // Parse value domain
            parseDomainForNodeWithColon(node.getRightChild(), domainStr, pos, isEx);

        } else if (node.getLeftChild() != null) {
            // list, set, tuple: expects outerRange(innerRange
            if (pos[0] >= domainStr.length() || domainStr.charAt(pos[0]) != '(') {
                throw new InvalidConfigException(
                    "Expected '(' for child domain in: " + domainStr);
            }
            pos[0]++;

            parseDomainForNode(node.getLeftChild(), domainStr, pos, isEx);
        }
        // For primitives (int, bool, float, str): no children, nothing more to consume
    }

    /**
     * Variant of parseDomainForNode that also stops at ':' (for dict key parsing).
     * This is needed to parse dict key domains which are terminated by ':'.
     */
    private void parseDomainForNodeWithColon(APyNode<?> node, String domainStr, int[] pos,
                                              boolean isEx) throws InvalidConfigException {
        // Read range spec until '(' or ':'
        int start = pos[0];
        while (pos[0] < domainStr.length()
                && domainStr.charAt(pos[0]) != '('
                && domainStr.charAt(pos[0]) != ':') {
            pos[0]++;
        }
        String rangeSpec = domainStr.substring(start, pos[0]);

        List<Number> domain = parseRangeSpec(rangeSpec);
        if (isEx) {
            node.setExDomain(domain);
        } else {
            node.setRanDomain(domain);
        }

        // Handle nested children (for nested containers inside dict key type)
        if (node instanceof PyDictNode) {
            if (pos[0] >= domainStr.length() || domainStr.charAt(pos[0]) != '(') {
                throw new InvalidConfigException(
                    "Expected '(' for nested dict child domain");
            }
            pos[0]++;
            parseDomainForNodeWithColon(node.getLeftChild(), domainStr, pos, isEx);
            if (pos[0] >= domainStr.length() || domainStr.charAt(pos[0]) != ':') {
                throw new InvalidConfigException(
                    "Expected ':' for nested dict value domain");
            }
            pos[0]++;
            parseDomainForNodeWithColon(node.getRightChild(), domainStr, pos, isEx);
        } else if (node.getLeftChild() != null) {
            if (pos[0] >= domainStr.length() || domainStr.charAt(pos[0]) != '(') {
                throw new InvalidConfigException(
                    "Expected '(' for nested child domain");
            }
            pos[0]++;
            parseDomainForNodeWithColon(node.getLeftChild(), domainStr, pos, isEx);
        }
    }

    /**
     * Parses a range spec string into a list of Numbers.
     * Supports "a~b" (inclusive range) and "[v1,v2,...]" (explicit list).
     *
     * @param spec the range spec string
     * @return the list of values
     * @throws InvalidConfigException if the spec is invalid
     */
    private List<Number> parseRangeSpec(String spec) throws InvalidConfigException {
        if (spec.isEmpty()) {
            throw new InvalidConfigException("Empty range spec");
        }
        if (spec.contains(" ")) {
            throw new InvalidConfigException("Space found in range spec: " + spec);
        }

        if (spec.startsWith("[")) {
            // Explicit list format: [v1,v2,...]
            if (!spec.endsWith("]")) {
                throw new InvalidConfigException("Missing ']' in range spec: " + spec);
            }
            String inner = spec.substring(1, spec.length() - 1);
            if (inner.isEmpty()) {
                throw new InvalidConfigException("Empty explicit list in range spec: " + spec);
            }
            String[] parts = inner.split(",");
            List<Number> values = new ArrayList<>();
            for (String part : parts) {
                values.add(parseNumber(part));
            }
            return values;
        } else {
            // Range format: a~b
            int tildeIdx = spec.indexOf('~');
            if (tildeIdx < 0) {
                throw new InvalidConfigException("Invalid range spec (no '~'): " + spec);
            }
            // Make sure there's only one tilde
            if (spec.indexOf('~', tildeIdx + 1) >= 0) {
                throw new InvalidConfigException(
                    "Multiple '~' in range spec: " + spec);
            }
            String lowerStr = spec.substring(0, tildeIdx);
            String upperStr = spec.substring(tildeIdx + 1);
            Number lower = parseNumber(lowerStr);
            Number upper = parseNumber(upperStr);
            if (lower.doubleValue() > upper.doubleValue()) {
                throw new InvalidConfigException(
                    "Lower bound > upper bound in range: " + spec);
            }
            // Generate integer range
            List<Number> values = new ArrayList<>();
            for (int i = lower.intValue(); i <= upper.intValue(); i++) {
                values.add(i);
            }
            return values;
        }
    }

    /**
     * Parses a string as a Number (integer or double).
     *
     * @param s the string to parse
     * @return the Number value
     * @throws InvalidConfigException if the string is not a valid number
     */
    private Number parseNumber(String s) throws InvalidConfigException {
        if (s.isEmpty()) {
            throw new InvalidConfigException("Empty number string");
        }
        try {
            return Integer.parseInt(s);
        } catch (NumberFormatException e) {
            try {
                return Double.parseDouble(s);
            } catch (NumberFormatException e2) {
                throw new InvalidConfigException("Invalid number: '" + s + "'");
            }
        }
    }
}

